const query  = $('Webhook — GET /vmm-sp-escalation-matrix').first().json.query || {};
const vendor = (query.vendor || '').toString().trim().toLowerCase();
const region = (query.region || '').toString().trim();
const level  = (query.level  || '').toString().trim();

const all = $input.all();

const contacts = all
  .map(item => ({
    vendorName:    (item.json['Vendor Name']      || '').trim(),
    region:        (item.json['Region']           || '').trim(),
    city:          (item.json['City']             || '').trim(),
    level:         (item.json['Escalation Level'] || '').trim(),
    contactPerson: (item.json['Contact Person']   || '').trim(),
    customerCareNo:(item.json['Customer Care No'] != null ? String(item.json['Customer Care No']) : '').trim(),
    mobile1:       (item.json['Mobile No 1']      != null ? String(item.json['Mobile No 1'])      : '').trim(),
    mobile2:       (item.json['Mobile No 2']      != null ? String(item.json['Mobile No 2'])      : '').trim(),
    mobile3:       (item.json['Mobile No 3']      != null ? String(item.json['Mobile No 3'])      : '').trim(),
    email:         (item.json['Email']            || '').trim(),
    status:        (item.json['Status']           || '').trim(),
  }))
  .filter(c => c.vendorName && c.status.toLowerCase() === 'active')
  .filter(c => !vendor || c.vendorName.toLowerCase().includes(vendor))
  .filter(c => !region || c.region.toLowerCase() === region.toLowerCase())
  .filter(c => !level  || c.level.toLowerCase()  === level.toLowerCase());

return [{ json: { success: true, count: contacts.length, contacts } }];
